 35→
 36→function normalizeString(input: unknown): string | null {
 37→  if (typeof input !== "string") return null;
 38→  const value = input.trim();
 39→  return value || null;
 40→}
 41→
 42→function parseDateIso(input: unknown): string | null {
 43→  if (!input) return null;
 44→  if (input instanceof Date) {
 45→    if (Number.isNaN(input.getTime())) return null;
 46→    return input.toISOString();
 47→  }
 48→  if (typeof input === "string" || typeof input === "number") {
 49→    const parsed = new Date(input);
 50→    if (Number.isNaN(parsed.getTime())) return null;
 51→    return parsed.toISOString();
 52→  }
 53→  return null;
 54→}
 55→
 56→function parseLocation(input: unknown): SubmissionLocation | null {
 57→  if (!input || typeof input !== "object") return null;
 58→  const location = input as { latitude?: unknown; longitude?: unknown };
 59→  const latitude = typeof location.latitude === "number" ? location.latitude : Number(location.latitude);
 60→  const longitude = typeof location.longitude === "number" ? location.longitude : Number(location.longitude);
 61→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 62→  return { latitude, longitude };
 63→}
 64→
 65→function parseOptionalNumber(input: unknown): number | null {
 66→  if (typeof input === "number" && Number.isFinite(input)) return input;
 67→  if (typeof input === "string") {
 68→    const parsed = Number(input);
 69→    if (Number.isFinite(parsed)) return parsed;
 70→  }
 71→  return null;
 72→}
 73→
 74→function parseOptionalBoolean(input: unknown): boolean | null {
 75→  if (typeof input === "boolean") return input;
 76→  return null;
 77→}
 78→
 79→function roundKm(input: number): number {
 80→  return Number(input.toFixed(KM_PRECISION));
 81→}
 82→
 83→export function haversineKm(a: SubmissionLocation, b: SubmissionLocation): number {
 84→  const toRad = (deg: number) => (deg * Math.PI) / 180;
 85→  const dLat = toRad(b.latitude - a.latitude);
 86→  const dLon = toRad(b.longitude - a.longitude);
 87→  const lat1 = toRad(a.latitude);
 88→  const lat2 = toRad(b.latitude);
 89→  const sinLat = Math.sin(dLat / 2);
 90→  const sinLon = Math.sin(dLon / 2);
 91→  const h = sinLat * sinLat + Math.cos(lat1) * Math.cos(lat2) * sinLon * sinLon;
 92→  return 2 * EARTH_RADIUS_KM * Math.atan2(Math.sqrt(h), Math.sqrt(1 - h));
 93→}
 94→
 95→export async function extractPhotoMetadata(imageBuffer: Buffer): Promise<ExtractedPhotoMetadata> {
 96→  const parsed = (await exifr.parse(imageBuffer, {
 97→    gps: true,
 98→    exif: true,
 99→    tiff: true,
100→  })) as Record<string, unknown> | null;
101→
102→  if (!parsed) {
103→    return {
104→      gps: null,
105→      capturedAt: null,
106→      deviceMake: null,
107→      deviceModel: null,
108→    };
109→  }
110→
111→  const latitude = typeof parsed.latitude === "number" ? parsed.latitude : Number(parsed.latitude);
112→  const longitude = typeof parsed.longitude === "number" ? parsed.longitude : Number(parsed.longitude);
113→  const gps = Number.isFinite(latitude) && Number.isFinite(longitude) ? { latitude, longitude } : null;
114→
115→  const capturedAt =
116→    parseDateIso(parsed.DateTimeOriginal) ??
117→    parseDateIso(parsed.DateTimeDigitized) ??
118→    parseDateIso(parsed.CreateDate) ??
119→    parseDateIso(parsed.ModifyDate);
120→
121→  return {
122→    gps,
123→    capturedAt,
124→    deviceMake: normalizeString(parsed.Make),
125→    deviceModel: normalizeString(parsed.Model),
126→  };
127→}
128→
129→function isHttpUrl(input: string): boolean {
130→  return /^https?:\/\//i.test(input);
131→}
132→
133→export async function extractPhotoMetadataFromUrl(photoUrl: string): Promise<ExtractedPhotoMetadata | null> {
134→  if (!photoUrl || !isHttpUrl(photoUrl)) return null;
135→
136→  const controller = new AbortController();
137→  const timeout = setTimeout(() => controller.abort(), REMOTE_FETCH_TIMEOUT_MS);
138→  try {
139→    const response = await fetch(photoUrl, { signal: controller.signal });
140→    if (!response.ok) return null;
141→    const arrayBuffer = await response.arrayBuffer();
142→    if (!arrayBuffer.byteLength || arrayBuffer.byteLength > MAX_REMOTE_METADATA_BYTES) return null;
143→    return await extractPhotoMetadata(Buffer.from(arrayBuffer));
144→  } catch {
145→    return null;
146→  } finally {
147→    clearTimeout(timeout);
148→  }
149→}
150→
151→export function buildPhotoFraudMetadata(params: BuildPhotoFraudMetadataParams): SubmissionPhotoMetadata | null {
152→  if (!params.extracted) return null;
153→
154→  const { extracted, submissionLocation, ipLocation, submissionMatchThresholdKm, ipMatchThresholdKm } = params;
155→  const gps = extracted.gps;
156→
157→  const submissionDistanceRaw = gps && submissionLocation ? haversineKm(submissionLocation, gps) : null;
158→  const ipDistanceRaw = gps && ipLocation ? haversineKm(ipLocation, gps) : null;
159→
160→  const submissionDistanceKm = submissionDistanceRaw === null ? null : roundKm(submissionDistanceRaw);
161→  const ipDistanceKm = ipDistanceRaw === null ? null : roundKm(ipDistanceRaw);
162→
163→  return {
164→    gps,
165→    capturedAt: extracted.capturedAt,
166→    deviceMake: extracted.deviceMake,
167→    deviceModel: extracted.deviceModel,
168→    submissionDistanceKm,
169→    submissionGpsMatch: submissionDistanceKm === null ? null : submissionDistanceKm <= submissionMatchThresholdKm,
170→    ipDistanceKm,
171→    ipGpsMatch: ipDistanceKm === null ? null : ipDistanceKm <= ipMatchThresholdKm,
172→  };
173→}
174→
175→export function buildSubmissionFraudCheck(params: BuildSubmissionFraudCheckParams): SubmissionFraudCheck {
176→  return {
177→    submissionLocation: params.submissionLocation,
178→    effectiveLocation: params.effectiveLocation,
179→    ipLocation: params.ipLocation,
180→    primaryPhoto: params.primaryPhoto,
181→    secondaryPhoto: params.secondaryPhoto,
182→    submissionMatchThresholdKm: params.submissionMatchThresholdKm,
183→    ipMatchThresholdKm: params.ipMatchThresholdKm,
184→  };
185→}
186→
187→function parsePhotoFraudMetadata(input: unknown): SubmissionPhotoMetadata | null {
188→  if (!input || typeof input !== "object") return null;
189→  const metadata = input as Record<string, unknown>;
190→
191→  return {
192→    gps: parseLocation(metadata.gps),
193→    capturedAt: parseDateIso(metadata.capturedAt),
194→    deviceMake: normalizeString(metadata.deviceMake),
195→    deviceModel: normalizeString(metadata.deviceModel),
196→    submissionDistanceKm: parseOptionalNumber(metadata.submissionDistanceKm),
197→    submissionGpsMatch: parseOptionalBoolean(metadata.submissionGpsMatch),
198→    ipDistanceKm: parseOptionalNumber(metadata.ipDistanceKm),
199→    ipGpsMatch: parseOptionalBoolean(metadata.ipGpsMatch),
200→  };
201→}
202→
203→export function parseSubmissionFraudCheck(input: unknown): SubmissionFraudCheck | null {
204→  if (!input || typeof input !== "object") return null;
205→  const fraudCheck = input as Record<string, unknown>;
206→  const effectiveLocation = parseLocation(fraudCheck.effectiveLocation);
207→  if (!effectiveLocation) return null;
208→
209→  const submissionMatchThresholdKm =
210→    parseOptionalNumber(fraudCheck.submissionMatchThresholdKm) ?? DEFAULT_SUBMISSION_GPS_MATCH_THRESHOLD_KM;
211→  const ipMatchThresholdKm = parseOptionalNumber(fraudCheck.ipMatchThresholdKm) ?? 50;
212→
213→  return {
214→    submissionLocation: parseLocation(fraudCheck.submissionLocation),
215→    effectiveLocation,
216→    ipLocation: parseLocation(fraudCheck.ipLocation),
217→    primaryPhoto: parsePhotoFraudMetadata(fraudCheck.primaryPhoto),
218→    secondaryPhoto: parsePhotoFraudMetadata(fraudCheck.secondaryPhoto),
219→    submissionMatchThresholdKm,
220→    ipMatchThresholdKm,
221→  };
222→}
