 88→function sanitizeClientDevice(input: unknown): ClientDeviceInfo | null {
 89→  if (!input || typeof input !== "object") return null;
 90→  const raw = input as Record<string, unknown>;
 91→  const deviceId = trimString(raw.deviceId, 128);
 92→  if (!deviceId) return null;
 93→  const platform = trimString(raw.platform, 64);
 94→  const userAgent = trimString(raw.userAgent, 256);
 95→  const memory = typeof raw.deviceMemoryGb === "number" && Number.isFinite(raw.deviceMemoryGb) ? raw.deviceMemoryGb : null;
 96→  const cpu = typeof raw.hardwareConcurrency === "number" && Number.isFinite(raw.hardwareConcurrency) ? raw.hardwareConcurrency : null;
 97→  const isLowEnd = raw.isLowEnd === true;
 98→
 99→  return {
100→    deviceId,
101→    platform: platform ?? undefined,
102→    userAgent: userAgent ?? undefined,
103→    deviceMemoryGb: memory,
104→    hardwareConcurrency: cpu,
105→    isLowEnd,
106→  };
