314→async function buildAdminSubmissionEvents(events: PointEvent[]): Promise<AdminSubmissionEvent[]> {
315→  const sortedEvents = [...events].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
316→  const userIds = Array.from(
317→    new Set(
318→      sortedEvents
319→        .map((event) => normalizeActorId(event.userId))
320→        .filter((value) => value.length > 0),
321→    ),
322→  );
323→
324→  const profileEntries = await Promise.all(
325→    userIds.map(async (userId) => [userId, await getUserProfile(userId)] as const),
326→  );
327→  const profileByUserId = new Map(profileEntries);
328→  const output: AdminSubmissionEvent[] = [];
329→  let fallbackLookups = 0;
330→
331→  for (const event of sortedEvents) {
332→    const normalizedUserId = normalizeActorId(event.userId);
333→    const profile = profileByUserId.get(normalizedUserId) ?? null;
334→    const emailFromProfile = typeof profile?.email === "string" ? profile.email.trim().toLowerCase() : "";
335→    const email = emailFromProfile || (normalizedUserId.includes("@") ? normalizedUserId : null);
336→    const name = getUserDisplayName(normalizedUserId, profile?.name ?? null, email);
337→    let fraudCheck = getEventFraudCheck(event);
338→    if (!fraudCheck && fallbackLookups < MAX_FORENSICS_FALLBACK_LOOKUPS) {
339→      fallbackLookups += 1;
340→      try {
341→        fraudCheck = await buildFallbackFraudCheck(event);
342→      } catch {
343→        fraudCheck = null;
344→      }
345→    }
346→
347→    output.push({
348→      event,
349→      user: {
350→        id: normalizedUserId || event.userId,
351→        name,
352→        email,
353→      },
354→      fraudCheck,
355→    });
356→  }
357→
358→  return output;
359→}
